var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【부록-003】 영상 기록#2</color>      ","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>……\\nCCN No. AS002M0035-04：<color=#ffd34c>【付録-003】 映像記録#2</color>      ","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【Appendix-003】 Video Record #2</color>      ","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR <color=#ffd34c>ALPHA CONFIRMED</color>      \\nCCN No. AS002M0035-04: <color=#ffd34c>【附錄-003】 影像記錄#2</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"으랏차아아아! 오늘 일도 이걸로 끝!","JPN":"よぉっしゃあああ！今日の仕事もこれにて終了だぜ！","ENG":"Haaaaa! That's it for today!","TWN":"啊啊啊啊啊啊啊啊啊啊啊！今天的工作結束了！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"다, 다들 고생했어......!","JPN":"み、みんなお疲れ様……！","ENG":"G-good work, everyone!","TWN":"各、各位辛苦了……！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그러게. 요새는 이리저리 많이 불려 다니는 것 같아.","JPN":"そうね。最近、いろんなところに引っ張り出されてるわ。","ENG":"Indeed. It seems like we are being sent everywhere these days.","TWN":"是啊，最近好像一直被使喚來使喚去的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 기세라면 정식 라이선스도 금방이지! 안 그래?","JPN":"この勢いなら正式ライセンスだってすぐに取れそうだな！そうだろ？","ENG":"We'll have our official licenses in no time! Right?","TWN":"照這個氣勢繼續下去，我們很快就會拿到正式執照了！對吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"으, 응!","JPN":"う、うん！","ENG":"Y-yeah!","TWN":"嗯、對！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"라이선스를 구실로 부려먹어도 상도덕은 지켜 주면 좋겠는데......","JPN":"ライセンスをダシにしてコキ使うのはまあいいとして、商道徳に反することはよしてほしいわよね……","ENG":"Even if they are overworking us for the license, I wish they would keep their business morality...","TWN":"就算是用執照當藉口要我們苦工，至少也該遵守商業道德才對吧……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"안 그래, 린?","JPN":"リンもそう思うでしょ？","ENG":"Don't you think so, Lin?","TWN":"對吧，琳？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"......린?","JPN":"……リン？","ENG":"Lin?","TWN":"……琳？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"왜 그래, 옷도 안 갈아입고? 무슨 일 있어?","JPN":"どうしたの？服も着替えてないじゃない。何かあったの？","ENG":"What's wrong? How come you're not changing? Did something happen?","TWN":"怎麼了，連衣服也不換？發生什麼事了嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"응?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아냐, 대장. 연구소에 다녀온 뒤로 어쩐지 계속 피곤해서.","JPN":"違うの、隊長。研究所に行ってから、何だか少し疲れてて。","ENG":"It's nothing, Cap. I'm just a bit tired after the trip to the lab.","TWN":"沒事，隊長。只是從研究所回來後，總覺得有點累。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"먼저 숙소에 가 있어. 조금 쉬다가 금방 갈게.","JPN":"先に宿舎に帰ってて。私は少しだけ休んで行くから。","ENG":"Go on and head back home first. I'll catch up after getting some rest.","TWN":"你們先回宿舍吧，我稍微休息一下就過去。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"연구소에 갔는데 피곤해? 너 운동 부족 아냐?","JPN":"研究所に行ったのに疲れたのか？お前、運動不足なんじゃねえの？","ENG":"You're tired from a trip to the lab? You should work out more.","TWN":"去了趟研究所後很累？妳這是運動不足吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아하하...... 저기, 유진아. 린도 기분이 안 좋은데 그런 말은......","JPN":"あはは……えっと、シロコ。リンは調子がよくないみたいだし、からかったりするのは……","ENG":"Ah hah hah... Um, Eujin. I don't think you should say that when Lin's not feeling well...","TWN":"啊哈哈……那個，劉珍。琳也有心情不好的時候，那種話就不要……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......그럴지도 모르겠네.","JPN":"……そうかもしれない。","ENG":"That might be true.","TWN":"……也許是那樣沒錯。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"힉......!","JPN":"ヒィッ……！","ENG":"Hic!","TWN":"咿……！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"리, 린아? 방금 그럴지도 모른다고 했어? 정말 괜찮은 거야?","JPN":"リ、リン？今、そうかもしれないって言った？本当に大丈夫なんだよね？","ENG":"L-Lin? Did you just say that it might be true? Are you sure you're okay?","TWN":"琳、琳？妳剛才說''也許是那樣沒錯''嗎？妳真的沒事嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"혹시 내가 약을 잘못 타 온 거 아닐까?","JPN":"ひょっとして私、お薬を間違えてもらってきたんじゃ……","ENG":"Did I give her the wrong medicine?","TWN":"該不會是我拿錯藥了？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장도 들었지?! 이 녀석 맛이 갔잖아!","JPN":"た、隊長も聞いただろ！？こいつ、普通じゃねえぞ！","ENG":"D-did you hear that, Cap?! She's gone completely nuts!","TWN":"隊、隊長也聽到了吧？！這傢伙怪怪的！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"박사 아줌마가 머리에 이상한 짓 한 거 아냐?","JPN":"あのおばさんに頭でもいじられたんじゃねえのか？","ENG":"That crazy professor must have done something weird to her.","TWN":"該不會是那個博士阿姨，對她的大腦做了什麼奇怪的事情吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐음...... 그 교수님은 그럴 시간 있으면 마스크 팩이나 한 장 더 바를 것 같은데......","JPN":"ふ～ん……あの教授、人にそんなことする暇があったら、自分の顔にパックでもしてそうだけど……","ENG":"Hmm... That professor would rather put on a face mask for her skin if she had the time to do that...","TWN":"嗯……那個教授有那種時間的話，應該會去多敷一張面膜吧……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"린, 무슨 일 있는 건 아니지?","JPN":"リン、何かあったわけじゃないのよね？","ENG":"Lin, are you sure you're okay?","TWN":"琳，發生什麼事了？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"응. 괜찮아. 그냥 옛날 생각이 났을 뿐이니까.","JPN":"うん、平気。少し、昔のことを思い出しただけだから。","ENG":"Yeah. I'm fine. I just remembered something from the past.","TWN":"嗯，我沒事，只是想起以前的事情而已。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"알겠어. 그래도 어디 아픈 것 같으면 얘기해 줘. 관리부장님에겐 내가 얘기해 둘게.","JPN":"わかったわ。でも、どこか具合が悪いようなら遠慮なく言ってちょうだい。管理部長には私から話しておくわ。","ENG":"Okay. But make sure to tell me if you're not feeling well. I'll talk to the Manager about your current status.","TWN":"知道了，如果覺得哪裡不舒服就告訴我，管理部長那邊我會去說的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......고마워, 대장.","JPN":"……ありがとう、隊長。","ENG":"Thanks, Cap.","TWN":"……謝謝妳，隊長。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"XIAOLIN_KID_NULL_NULL","text":{"KOREA":"예쁜 새......","JPN":"きれいな鳥……","ENG":"Pretty bird...","TWN":"好漂亮的鳥……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"그렇네. 깃털 색이 정말 예쁜걸.","JPN":"ああ、そうだね。羽根の色がとても綺麗だ。","ENG":"Yeah. It has really colorful feathers.","TWN":"是啊，羽毛的顏色真是漂亮呢。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"이런 데에 둥지를 틀다니, 신기해라.","JPN":"こんなところに巣を作るなんて珍しいな。","ENG":"That's odd that the bird created a nest here.","TWN":"居然在這種地方築巢，真是神奇。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"그치만 곤란한걸. 여기 있으면 금방 다른 직원들이 둥지를 걷어 버릴 거야.","JPN":"しかし困ったな。ここに巣を作られたら、すぐに他の職員に片付けられてしまうだろう。","ENG":"But this could be a problem. The employees will take the nest down if it stays here.","TWN":"但真是傷腦筋，在這裡築巢的話，馬上就會被別的員工清理掉的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"XIAOLIN_KID_NULL_NULL","text":{"KOREA":"어......? 정말......?","JPN":"え……？ほんと……？","ENG":"Huh? Really?","TWN":"啊……？真的……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_KID_NULL_NULL","text":{"KOREA":"저렇게 예쁜데...... 어른들은 새를 싫어해......?","JPN":"あんなにきれいなのに……大人たちは鳥が嫌いなの……？","ENG":"But it's so pretty... Don't adults like birds?","TWN":"明明那麼漂亮……大人討厭鳥嗎……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"그렇지 않아. 여기 있는 어른들은 모두 저런 걸 오래오래 간직하고 싶어서 모였거든.","JPN":"そうじゃないさ。ここにいる大人たちは、みんなああいったものをいつまでも大事にしたいと思って集まってるんだ。","ENG":"Yes, they do. All of the adults in here are trying to protect things like that for a long time.","TWN":"不是這樣的。所有大人都是為了長久地守護這些事物，才聚集在這裡的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"하지만 이곳은 연구 시설이란다. 저런 작은 새도 연구에 방해될 수 있어.","JPN":"ただ、ここは研究施設だからね。あんな小さな鳥だって研究の邪魔になりかねない。","ENG":"But this is a research facility. Even a small bird like that could become a nuisance.","TWN":"但是，這裡是研究設施。就算是那樣的小鳥，也會妨礙到研究的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"실패하면 다들 슬퍼하겠지. 많은 사람들이 함께 노력하고 있는 연구니까.","JPN":"もし研究が失敗してしまったら、みんな悲しむことになる。たくさんの人が頑張ってきた研究なんだから。","ENG":"If anything fails, everyone will be sad. This research is the combined effort of many people.","TWN":"如果失敗的話，大家會很傷心的。因為那是大家一起努力的研究。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"저 새도 둥지를 잃으면 슬프겠지만, 우리들이 하려는 일을 알면 이해해 줄 거야.","JPN":"あの鳥も巣を失ったら悲しいだろうけど、我々がしようとしていることを知れば、きっと理解してくれるはずさ。","ENG":"It would be sad for that bird to lose its nest, but it will understand once it realizes what we are doing here.","TWN":"如果那隻鳥失去了鳥巢，牠也會很傷心吧。但在知道我們想做的事情後，牠也一定會理解的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"XIAOLIN_KID_NULL_NULL","text":{"KOREA":"그래도......","JPN":"でも……","ENG":"But still...","TWN":"就算這樣……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"흐음......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TEACHER2_EXTRA_NULL_NULL","text":{"KOREA":"별일이네. 연구소에 왔을 때부터 비명 한 번 지르지 않던 네가......","JPN":"興味深いね。研究所に来た日から今まで、悲鳴一つ上げなかった君が……","ENG":"That's strange. You never even screamed once after arriving at the lab, yet you care so much for this bird...","TWN":"真是稀奇呢。到這個研究所後，連一聲慘叫都沒發出的妳……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TEACHER3_EXTRA_NULL_NULL","text":{"KOREA":"좋아. 자, ███. 우리 이렇게 하자.","JPN":"いいだろう。さあ、█████。ならこうしよう。","ENG":"Okay then. Listen, ███. Why don't we do this?","TWN":"很好。那麼，███，我們就這麼做吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TEACHER3_EXTRA_NULL_NULL","text":{"KOREA":"엄마새가 조금 화를 내겠지만, 둥지를 연구소에서 조금 떨어진 곳으로 옮겨 주는 거야.","JPN":"母鳥は少々機嫌を悪くするかもしれないが、研究所から少し離れた場所に巣を移してあげよう。","ENG":"The mother bird might get a bit angry, but you can move the nest to a location away from the lab.","TWN":"雖然鳥媽媽會有點生氣，但我們把鳥巢搬到離研究所稍微遠一點的地方吧。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TEACHER3_EXTRA_NULL_NULL","text":{"KOREA":"그럼 모두가 좋아하겠지?","JPN":"そうすれば、誰も悲しまずに済むだろう？","ENG":"Then everyone will be happy.","TWN":"這不是皆大歡喜嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_KID_NULL_NULL","text":{"KOREA":"정말? 그래도 돼......?","JPN":"ほんと？そうしてもいいの……？","ENG":"Really? Can I do that?","TWN":"真的？那樣也可以嗎……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TEACHER3_EXTRA_NULL_NULL","text":{"KOREA":"물론이고 말고.","JPN":"もちろんだとも。","ENG":"Of course you can.","TWN":"當然可以。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TEACHER3_EXTRA_NULL_NULL","text":{"KOREA":"대신, 나랑 약속하자.","JPN":"その代わり、約束してもらうよ。","ENG":"But, promise me one thing.","TWN":"不過，妳要先答應我。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TEACHER3_EXTRA_NULL_NULL","text":{"KOREA":"█겨.","JPN":"█くんだ。","ENG":"Pull the ███.","TWN":"開█。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......사기꾼.","JPN":"……ペテン師。","ENG":"Liar.","TWN":"……騙子。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};